#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool isIsomorphic(string s, string t) {
        if (s.size() != t.size()) return false;
        unordered_map<char, char> map_st;
        unordered_map<char, char> map_ts;
        for (size_t i = 0; i < s.size(); ++i) {
            char cs = s[i];
            char ct = t[i];
            auto it1 = map_st.find(cs);
            if (it1 != map_st.end()) {
                if (it1->second != ct) return false;
            } else {
                map_st[cs] = ct;
            }
            auto it2 = map_ts.find(ct);
            if (it2 != map_ts.end()) {
                if (it2->second != cs) return false;
            } else {
                map_ts[ct] = cs;
            }
        }
        return true;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int dummy;
    if (!(cin >> dummy)) return 0;
    string s, t;
    if (!(cin >> s)) return 0;
    if (!(cin >> t)) return 0;
    Solution sol;
    bool ans = sol.isIsomorphic(s, t);
    cout << (ans ? "true" : "false");
    return 0;
}
